import * as React from 'react';
import { AppProvider } from '@mui/toolpad';
import { SignInPage } from '@mui/toolpad/components';
import { createTheme } from '@mui/material/styles';
import { CssBaseline } from '@mui/material';

const providers = [
  { id: 'credentials', name: 'Email and Password' },
  { id: 'github', name: 'GitHub' },
  { id: 'google', name: 'Google' },
];

const signIn = async (provider) => {
  const result = await new Promise((resolve) => {
    setTimeout(() => {
      console.log(`Signing in with: ${provider.id}`);
      // You can simulate success or error here
      resolve({ error: provider.id === 'credentials' ? '' : 'Mock error' });
    }, 500);
  });
  return result;
};

const theme = createTheme({
  palette: {
    mode: 'light',
    primary: {
      main: '#3f51b5',
    },
  },
});

export default function LogIn() {
  return (
    <AppProvider theme={theme}>
      <CssBaseline />
      <SignInPage
        signIn={signIn}
        providers={providers}
        slotProps={{ form: { noValidate: true } }}
        sx={{
          '& form > .MuiStack-root': {
            marginTop: '2rem',
            rowGap: '0.5rem',
          },
        }}
      />
    </AppProvider>
  );
}
